286	      await user.click(input);
287	      await user.type(input, 'Option 1');
288	
289	      await waitFor(() => {
290	        expect(screen.getByText('Option 1')).toBeInTheDocument();
291	        expect(screen.queryByText('Create "Option 1"')).not.toBeInTheDocument();
292	      });
293	    });
294	  });
295	
296	  describe('No Options/Results Messages', () => {
297	    test('shows custom no options message when no options are provided', async () => {
298	      const user = userEvent.setup();
299	      const customMessage = 'Custom no options message';
300	      render(
301	        <TypeaheadSelect options={[]} onChange={mockOnChange} noOptionsMessage={customMessage} popperProps={{ appendTo: 'inline' }} />,
302	      );
303	
304	      const input = screen.getByRole('combobox');
305	      await user.click(input);
306	
307	      await waitFor(() => {
308	        expect(screen.getByText(customMessage)).toBeInTheDocument();
309	      });
310	    });
311	
312	    test('shows custom no results message when filtering returns no results', async () => {
313	      const user = userEvent.setup();
314	      const customMessage = (filter: string) => `Custom no results for "${filter}"`;
315	      render(<TypeaheadSelect {...defaultProps} noResultsMessage={customMessage} />);
316	
317	      const input = screen.getByRole('combobox');
318	      await user.click(input);
319	      await user.type(input, 'nonexistent');
320	
321	      await waitFor(() => {
322	        expect(screen.getByText('Custom no results for "nonexistent"')).toBeInTheDocument();
323	      });
324	    });
325	  });
326	
327	  describe('Keyboard Navigation', () => {
328	    test('selects option with Enter key', async () => {
329	      const user = userEvent.setup();
330	      render(<TypeaheadSelect {...defaultProps} />);
331	
332	      const input = screen.getByRole('combobox');
333	      await user.click(input);
334	
335	      // Navigate to second option and press Enter
336	      await user.keyboard('{ArrowDown}{ArrowDown}{Enter}');
337	
338	      expect(mockOnChange).toHaveBeenCalledWith('option2');
339	    });
340	
341	    test('closes dropdown with Escape key', async () => {
342	      const user = userEvent.setup();
343	      render(<TypeaheadSelect {...defaultProps} />);
344	
345	      const input = screen.getByRole('combobox');
346	      await user.click(input);
347	
348	      // Verify dropdown is open
349	      expect(input).toHaveAttribute('aria-expanded', 'true');
350	
351	      await user.keyboard('{Escape}');
352	
