363	      render(<TypeaheadSelect {...defaultProps} />);
364	
365	      const input = screen.getByRole('combobox');
366	      const toggleButton = screen.getByRole('button', { name: /menu toggle/i });
367	
368	      // Initially closed
369	      expect(input).toHaveAttribute('aria-expanded', 'false');
370	
371	      // Click toggle to open
372	      await user.click(toggleButton);
373	      expect(input).toHaveAttribute('aria-expanded', 'true');
374	
375	      // Click toggle to close
376	      await user.click(toggleButton);
377	      await waitFor(() => {
378	        expect(input).toHaveAttribute('aria-expanded', 'false');
379	      });
380	    });
381	  });
382	});

