  1	import {
  2	  type ForwardedRef,
  3	  forwardRef,
  4	  type ReactNode,
  5	  useImperativeHandle,
  6	  useMemo,
  7	  useRef,
  8	  useState,
  9	} from 'react';
 10	
 11	import {
 12	  MenuFooter,
 13	  type MenuToggleProps,
 14	  Select,
 15	  SelectList,
 16	  SelectOption,
 17	  type SelectProps,
 18	} from '@patternfly/react-core';
 19	import { isEmpty } from '@utils/helpers';
 20	
 21	import { DEFAULT_NO_OPTIONS, DEFAULT_PLACEHOLDER, PLACEHOLDER_VALUES } from './utils/constants';
 22	import type { TypeaheadSelectOption } from './utils/types';
 23	import {
 24	  defaultFilterFunction,
 25	  generateFilteredOptions,
 26	  getDefaultCreateMessage,
 27	  getDefaultNoResults,
 28	  isPlaceholderValue,
 29	} from './utils/utils';
 30	import TypeaheadMenuToggle from './TypeaheadMenuToggle';
 31	
 32	type TypeaheadSelectProps = {
 33	  options: TypeaheadSelectOption[];
 34	  value?: string | number;
 35	  onChange: (value: string | number | undefined) => void;
 36	  onInputChange?: (inputValue: string) => void;
 37	  filterFunction?: (
 38	    filterValue: string,
 39	    options: TypeaheadSelectOption[],
 40	  ) => TypeaheadSelectOption[];
 41	  allowClear?: boolean;
 42	  placeholder?: string;
 43	  isCreatable?: boolean;
 44	  createOptionMessage?: string | ((value: string) => string);
 45	  noOptionsMessage?: string;
 46	  emptyState?: ReactNode;
 47	  noResultsMessage?: string | ((filter: string) => string);
 48	  footer?: ReactNode;
 49	  isDisabled?: boolean;
 50	  toggleWidth?: string;
 51	  toggleProps?: Omit<MenuToggleProps, 'ref' | 'onClick' | 'isExpanded'>;
 52	  filterControls?: ReactNode;
 53	  testId?: string;
 54	} & Omit<SelectProps, 'toggle' | 'onSelect' | 'selected'>;
 55	
 56	const TypeaheadSelect = (
 57	  {
 58	    allowClear = false,
 59	    createOptionMessage = getDefaultCreateMessage,
 60	    emptyState,
 61	    filterControls,
 62	    filterFunction = defaultFilterFunction,
 63	    footer,
 64	    isCreatable = false,
 65	    isDisabled = false,
 66	    noOptionsMessage = DEFAULT_NO_OPTIONS,
 67	    noResultsMessage = getDefaultNoResults,
 68	    onChange,
 69	    onInputChange,
 70	    options = [],
 71	    placeholder = DEFAULT_PLACEHOLDER,
 72	    testId,
 73	    toggleProps,
 74	    toggleWidth,
 75	    value,
 76	    ...selectProps
 77	  }: TypeaheadSelectProps,
 78	  ref: ForwardedRef<HTMLInputElement>,
 79	) => {
 80	  const [isOpen, setIsOpen] = useState(false);
 81	  const [isFiltering, setIsFiltering] = useState(false);
 82	  const [inputValue, setInputValue] = useState('');
 83	  const inputRef = useRef<HTMLInputElement>(null);
 84	
 85	  useImperativeHandle(ref, () => inputRef.current!, []);
 86	
 87	  const selectedOption = useMemo(
 88	    () => options.find((option) => option.value === value),
 89	    [options, value],
 90	  );
 91	
 92	  const filteredOptions = useMemo(
 93	    () =>
 94	      generateFilteredOptions({
 95	        createOptionMessage,
 96	        filterFunction,
 97	        inputValue,
 98	        isCreatable,
 99	        isFiltering,
100	        noResultsMessage,
101	        options,
102	      }),
103	    [
104	      isFiltering,
105	      inputValue,
106	      options,
107	      filterFunction,
108	      isCreatable,
109	      createOptionMessage,
110	      noResultsMessage,
111	    ],
112	  );
113	
114	  // Show filtered options when filtering, all options when not, or no options message
115	  const displayOptions = useMemo(() => {
116	    if (isEmpty(options)) {
117	      return [
118	        {
119	          content: noOptionsMessage,
120	          optionProps: { isDisabled: true },
121	          value: PLACEHOLDER_VALUES.NO_OPTIONS,
122	        },
123	      ];
124	    }
125	    return filteredOptions;
126	  }, [options, filteredOptions, noOptionsMessage]);
127	
128	  const handleSelect = (selectedValue: string | number | undefined): void => {
129	    if (isPlaceholderValue(selectedValue)) {
130	      return;
131	    }
132	
133	    // Check if this is a create action or existing option
134	    const existingOption = options.find((option) => option.value === selectedValue);
135	
136	    if (existingOption || isCreatable) {
137	      onChange(selectedValue);
138	      setIsOpen(false);
139	      setIsFiltering(false);
140	      setInputValue(existingOption?.content?.toString() ?? selectedValue?.toString() ?? '');
141	    }
142	  };
143	
144	  return (
145	    <Select
146	      isOpen={isOpen}
147	      onSelect={(_, selectedValue) => {
148	        handleSelect(selectedValue);
149	      }}
150	      onOpenChange={(open) => {
151	        if (!open) {
152	          setIsOpen(false);
153	        }
154	      }}
155	      toggle={(toggleRef) => (
156	        <TypeaheadMenuToggle
157	          toggleRef={toggleRef}
158	          inputRef={inputRef}
159	          placeholder={placeholder}
160	          isDisabled={isDisabled}
161	          isOpen={isOpen}
162	          toggleWidth={toggleWidth}
163	          allowClear={allowClear}
164	          selectedOption={selectedOption}
165	          isFiltering={isFiltering}
166	          inputValue={inputValue}
167	          onInputChange={onInputChange}
168	          onSelectionClear={() => {
169	            setInputValue('');
170	            onChange('');
171	          }}
172	          onToggleClick={() => {
173	            if (isOpen) {
174	              // Reset filtering state when closing
175	              setIsFiltering(false);
176	              setInputValue(selectedOption?.content?.toString() ?? '');
177	            }
178	            setIsOpen((prev) => !prev);
179	          }}
180	          onInputValueChange={(newInputValue: string, newIsFiltering: boolean): void => {
181	            setInputValue(newInputValue);
182	            setIsFiltering(newIsFiltering);
183	          }}
184	          toggleProps={toggleProps}
185	          testId={testId}
186	        />
187	      )}
188	      shouldFocusFirstItemOnOpen={false}
189	      {...selectProps}
190	    >
191	      {isEmpty(options) && emptyState ? (
192	        emptyState
193	      ) : (
194	        <>
195	          {filterControls}
196	          <SelectList id="typeahead-listbox">
197	            {displayOptions.map((option) => (
198	              <SelectOption key={option.value} value={option.value} {...option.optionProps}>
199	                {option.content}
200	              </SelectOption>
201	            ))}
202	          </SelectList>
203	          {footer && (
204	            <MenuFooter
205	              onClick={() => {
206	                setIsOpen(false);
207	              }}
208	            >
209	              {footer}
210	            </MenuFooter>
211	          )}
212	        </>
213	      )}
214	    </Select>
215	  );
216	};
217	
218	export default forwardRef(TypeaheadSelect);

